std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create write operation for Event objects
  auto write_op = sqlgen::write(events);

  // 3. Execute write operation to insert events into database
  write_op(conn).value();

  // 4. Construct SELECT query with date/time extraction operations
  auto query = sqlgen::select_from<Event>(
    "event_id"_c,
    "event_name"_c,
    sqlgen::day("start_time"_c).as<"start_day">(),
    sqlgen::month("start_time"_c).as<"start_month">(),
    sqlgen::year("start_time"_c).as<"start_year">(),
    sqlgen::hour("start_time"_c).as<"start_hour">(),
    sqlgen::minute("start_time"_c).as<"start_minute">(),
    sqlgen::second("start_time"_c).as<"start_second">(),
    sqlgen::weekday("start_time"_c).as<"start_weekday">(),
    sqlgen::unixepoch("start_time"_c).as<"start_epoch">(),
    sqlgen::days_between("start_time"_c, "end_time"_c).as<"duration_days">()
  );

  // 5. Apply WHERE condition to filter events with end_time values
  query = query | sqlgen::where("end_time"_c.is_not_null());

  // 6. Execute query and transform results to TemporalAnalysis objects
  auto results = query(conn).value();

  // 7. Return the analysis results
  std::vector<TemporalAnalysis> analysis_results;
  for (const auto& row : results) {
    TemporalAnalysis analysis;
    analysis.event_id = row.event_id;
    analysis.event_name = row.event_name;
    analysis.start_day = row.start_day;
    analysis.start_month = row.start_month;
    analysis.start_year = row.start_year;
    analysis.start_hour = row.start_hour;
    analysis.start_minute = row.start_minute;
    analysis.start_second = row.start_second;
    analysis.start_weekday = row.start_weekday;
    analysis.start_epoch = row.start_epoch;
    analysis.duration_days = row.duration_days;
    analysis_results.push_back(analysis);
  }

  return analysis_results;
}

