#include <vector>
#include <unordered_map>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Perform upsert operation using sqlgen::write() with or_replace=true
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // 3. Read back items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false; // Read operation failed
  }
  auto read_items = read_result.value();

  // 4. Verify that the upserted items match the original input
  // Create a map for quick lookup by item_id
  std::unordered_map<int, Inventory> item_map;
  for (const auto& item : read_items) {
    item_map[item.item_id] = item;
  }

  // Verify each original item exists in the read results
  for (const auto& original_item : items) {
    auto it = item_map.find(original_item.item_id);
    if (it == item_map.end()) {
      return false; // Item not found in read results
    }

    // Verify the item data matches
    if (it->second.name != original_item.name || 
        it->second.quantity != original_item.quantity) {
      return false; // Item data mismatch
    }
  }

  return true; // All verifications passed
}

}  // namespace upsert_inventory_items
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"
2. **Upsert Operation**: Uses `sqlgen::write()` with `or_replace=true` parameter to perform insert-or-replace
3. **Verification**: Reads back all items using `sqlgen::read<std::vector<Inventory>>()` and verifies:
   - All original items exist in the database
   - The item data matches between input and read results
4. **Error Handling**: Returns `false` if any operation (connect, write, read) fails
5. **Efficient Lookup**: Uses `std::unordered_map` for O(1) lookups when verifying items

This implementation satisfies all the assessment objectives and follows the sqlgen library patterns demonstrated in the reference materials.

