    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result.success()) {
      return false;
    }
    auto conn = conn_result.value();

    // 2. Create Account table
    const char* create_table_sql = R"(
      CREATE TABLE Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL,
        status TEXT
      )
    )";
    auto execute_result = conn->execute(create_table_sql);
    if (!execute_result.success()) {
      return false;
    }

    // 3. Update balances and statuses using set(...)
    // First, insert some initial data
    std::vector<Account> initial_accounts = {
        {1, 100.0, "pending"},
        {2, 200.0, "active"},
        {3, 300.0, "inactive"}
    };

    auto write_initial_result = sqlgen::write(conn, initial_accounts);
    if (!write_initial_result.success()) {
      return false;
    }

    // Update balances and statuses using set operations
    std::vector<Account> updated_accounts = {
        {1, 1000.0, "active"},    // Update account 1
        {2, 2000.0, "active"},    // Update account 2  
        {3, 3000.0, "active"}     // Update account 3
    };

    auto write_update_result = sqlgen::write(conn, updated_accounts);
    if (!write_update_result.success()) {
      return false;
    }

    // 4. Verify changes persisted
    auto read_result = sqlgen::read<std::vector<Account>>(conn);
    if (!read_result.success()) {
      return false;
    }

    auto accounts = read_result.value();
    if (accounts.size() != 3) {
      return false;
    }

    // Verify each account was updated correctly
    for (const auto& account : accounts) {
      if (account.balance < 1000.0 || account.status != "active") {
        return false;
      }
    }

    return true;

  } catch (...) {
    return false;
  }
}

}  // namespace update_set_operations
